import { client, task } from "@trigger.dev/sdk";

client.initialize({
  id: "retry-project",
  apiKey: process.env.TRIGGER_API_KEY,
});

export const unreliableFetchTask = task({
  id: "unreliable-fetch-task_with_retries__yrj7snN",
  retry: {
    maxAttempts: 5,
    minTimeoutInMs: 1000,
    maxTimeoutInMs: 10000,
    factor: 2,
  },
  run: async ({ payload }) => {
    const response = await retry.fetch("https://httpbin.org/status/500,200", {
      retry: {
        maxAttempts: 5,
        minTimeoutInMs: 1000,
        maxTimeoutInMs: 10000,
        factor: 2,
        statusCodes: [500, 501, 502, 503, 504, 505, 506, 507, 508, 510, 511, 599],
      },
    });

    if (!response.ok) {
      throw new Error(`Request failed with status ${response.status}`);
    }

    return await response.json();
  },
});

